            return FfiConverterTypeAddressInfo.lift(
    callWithPointer {
    uniffiRustCallWithError(RlnException) { _status ->
    UniffiLib.INSTANCE.uniffi_rgb_lightning_node_fn_method_sdknode_address(
        it, _status)
}
    }
    )
    }
    

    
