/**
 * @suppress
 */
public object FfiConverterTypeSdkNode: FfiConverter<SdkNode, Pointer> {

    override fun lower(value: SdkNode): Pointer {
        return value.uniffiClonePointer()
    }

    override fun lift(value: Pointer): SdkNode {
        return SdkNode(value)
    }

    override fun read(buf: ByteBuffer): SdkNode {
        // The Rust code always writes pointers as 8 bytes, and will
        // fail to compile if they don't fit.
        return lift(Pointer(buf.getLong()))
    }

    override fun allocationSize(value: SdkNode) = 8UL

    override fun write(value: SdkNode, buf: ByteBuffer) {
        // The Rust code always expects pointers written as 8 bytes,
        // and will fail to compile if they don't fit.
        buf.putLong(Pointer.nativeValue(lower(value)))
    }
}



