sealed class RlnException(message: String): kotlin.Exception(message) {
        
        class NotInitialized(message: String) : RlnException(message)
        
        class InvalidRequest(message: String) : RlnException(message)
        
        class NotFound(message: String) : RlnException(message)
        
        class Conflict(message: String) : RlnException(message)
        
        class Internal(message: String) : RlnException(message)
        

    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<RlnException> {
        override fun lift(error_buf: RustBuffer.ByValue): RlnException = FfiConverterTypeRlnError.lift(error_buf)
    }
}

/**
 * @suppress
 */
public object FfiConverterTypeRlnError : FfiConverterRustBuffer<RlnException> {
    override fun read(buf: ByteBuffer): RlnException {
        
            return when(buf.getInt()) {
            1 -> RlnException.NotInitialized(FfiConverterString.read(buf))
            2 -> RlnException.InvalidRequest(FfiConverterString.read(buf))
            3 -> RlnException.NotFound(FfiConverterString.read(buf))
            4 -> RlnException.Conflict(FfiConverterString.read(buf))
            5 -> RlnException.Internal(FfiConverterString.read(buf))
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
        
    }

    override fun allocationSize(value: RlnException): ULong {
        return 4UL
    }

    override fun write(value: RlnException, buf: ByteBuffer) {
        when(value) {
            is RlnException.NotInitialized -> {
                buf.putInt(1)
                Unit
            }
            is RlnException.InvalidRequest -> {
                buf.putInt(2)
                Unit
            }
            is RlnException.NotFound -> {
                buf.putInt(3)
                Unit
            }
            is RlnException.Conflict -> {
                buf.putInt(4)
                Unit
            }
            is RlnException.Internal -> {
                buf.putInt(5)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}




